/** 每次读取环境变量，便于同一进程内测试脚本切换 MOCK / 提供商 */
function isMockMode() {
    return process.env.MOCK_MODE === 'true';
}

function currentLlmProvider(explicit) {
    return explicit || process.env.LLM_PROVIDER || 'bailian';
}

function hasLlmApiKey(providerName) {
    const p = providerName || currentLlmProvider();
    if (process.env.LLM_API_KEY) return true;
    return !!process.env[`${String(p).toUpperCase()}_API_KEY`];
}

// ==================== 主入口 ====================

exports.handler = async (event, context) => {
    try {
        const rawBody = typeof event.body === 'string' ? event.body : JSON.stringify(event.body || {});
        
        let body;
        try {
            body = rawBody ? JSON.parse(rawBody) : {};
        } catch (parseError) {
            log('ERROR', '请求 JSON 解析失败:', parseError.message);
            return response(400, { success: false, error: 'Invalid JSON body' });
        }

        const action = body.action;
        if (!action) {
            return response(400, { success: false, error: 'Missing action' });
        }
        
        log('INFO', `收到请求：${action}`);
        
        switch (action) {
            // 热点相关
            case 'get_hotspots':
                return await getHotspots(body);
            
            // 实时搜索热点
            case 'search_hotspots':
                return await searchHotspots(body);
            
            // 获取微博热搜
            case 'get_weibo_hot':
                return response(200, {
                    success: true,
                    data: await getWeiboHotRealtime(body)
                });
            
            // 获取知乎热榜
            case 'get_zhihu_hot':
                return response(200, {
                    success: true,
                    data: await getZhihuHotRealtime(body)
                });
            
            // 获取抖音热点
            case 'get_douyin_hot':
                return response(200, {
                    success: true,
                    data: await getDouyinHotRealtime(body)
                });
            
            // 获取百度热搜
            case 'get_baidu_hot':
                return response(200, {
                    success: true,
                    data: await getBaiduHotRealtime(body)
                });
            
            case 'analyze_hotspot':
                return await analyzeHotspot(body);
            
            // 脚本生成
            case 'generate_script':
                return await generateScript(body);
            
            // 视频生成
            case 'generate_video':
                return await generateVideo(body);
            
            // YouTube 上传
            case 'upload_to_youtube':
                return await uploadToYouTube(body);
            
            // 微信发布
            case 'publish_wechat':
                return await publishWeChat(body);
            
            // 微信一键生成
            case 'auto_create_wechat':
                return await autoCreateWeChatArticle(body);
            
            // 完整流程（一键式）
            case 'auto_create':
                return await autoCreateContent(body);
            
            // 频道管理
            case 'list_videos':
                return await listYouTubeVideos();
            
            case 'delete_video':
                return await deleteYouTubeVideo(body);
            
            // 健康检查
            case 'health':
                return response(200, { 
                    success: true, 
                    status: 'healthy',
                    timestamp: new Date().toISOString(),
                    mock: isMockMode()
                });
            
            default:
                return response(400, { success: false, error: 'Unknown action' });
        }
    } catch (error) {
        log('ERROR', '未处理异常:', error);
        return response(500, { 
            success: false, 
            error: error.message
        });
    }
};

// ==================== 热点获取模块 ====================

/**
 * 获取全网热点
 */
async function getHotspots(body) {
    const { platform = 'all', limit = 10 } = body;
    
    const hotspots = {
        weibo: [],
        douyin: [],
        youtube: [],
        twitter: [],
        zhihu: [],
        baidu: []
    };
    
    if (platform === 'all' || platform === 'weibo') {
        hotspots.weibo = await getWeiboHotRealtime({ limit });
    }
    
    if (platform === 'all' || platform === 'douyin') {
        hotspots.douyin = await getDouyinHotRealtime({ limit });
    }
    
    if (platform === 'all' || platform === 'zhihu') {
        hotspots.zhihu = await getZhihuHotRealtime({ limit });
    }
    
    if (platform === 'all' || platform === 'baidu') {
        hotspots.baidu = await getBaiduHotRealtime({ limit });
    }
    
    if (platform === 'all' || platform === 'youtube') {
        hotspots.youtube = await getYouTubeTrending(limit);
    }
    
    if (platform === 'all' || platform === 'twitter') {
        hotspots.twitter = await getTwitterTrending(limit);
    }
    
    return response(200, {
        success: true,
        data: hotspots,
        timestamp: new Date().toISOString()
    });
}

/**
 * 实时搜索热点（聚合搜索）
 */
async function searchHotspots(body) {
    const { keyword, platforms = ['weibo', 'zhihu', 'baidu'], limit = 10 } = body;
    
    if (!keyword) {
        throw new Error('缺少搜索关键词');
    }
    
    log('INFO', `实时搜索热点：${keyword}`);
    
    const results = {};
    
    // 并行搜索多个平台
    const searchTasks = platforms.map(async (platform) => {
        try {
            if (platform === 'weibo') {
                results.weibo = await searchWeibo(keyword, limit);
            } else if (platform === 'zhihu') {
                results.zhihu = await searchZhihu(keyword, limit);
            } else if (platform === 'baidu') {
                results.baidu = await searchBaidu(keyword, limit);
            }
        } catch (error) {
            log('ERROR', `${platform} 搜索失败:`, error.message);
            results[platform] = [];
        }
    });
    
    await Promise.all(searchTasks);
    
    return response(200, {
        success: true,
        data: results,
        keyword,
        timestamp: new Date().toISOString()
    });
}

/**
 * 获取微博热搜（实时）
 */
async function getWeiboHotRealtime(body) {
    const { limit = 10 } = body;
    
    if (isMockMode()) {
        log('INFO', 'MOCK_MODE 启用，返回模拟微博热搜数据');
        return Array.from({ length: limit }).map((_, i) => ({
            platform: 'weibo',
            title: `微博热搜示例主题 ${i + 1}`,
            rank: i + 1,
            hot_value: 100000 - i * 1234,
            url: 'https://weibo.com'
        }));
    }
    
    try {
        // 使用第三方 API 或爬虫获取微博热搜
        // 这里使用示例数据，实际部署时替换为真实 API
        const response = await axios.get('https://weibo.com/ajax/side/hotSearch', {
            headers: {
                'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
            },
            timeout: 5000
        });
        
        const data = response.data.data || [];
        return data.slice(0, limit).map(item => ({
            platform: 'weibo',
            title: item.word,
            rank: item.rank,
            hot_value: item.num,
            url: `https://s.weibo.com/weibo?q=${encodeURIComponent(item.word)}`,
            icon: item.icon,
            trend: item.flag_desc
        }));
    } catch (error) {
        log('ERROR', '获取微博热搜失败:', error.message);
        // 降级方案：返回缓存数据
        return [];
    }
}

