// ==================== AI 分析模块 ====================

/**
 * 分析热点话题
 */
async function analyzeHotspot(body) {
    const { topic, platform, hot_value } = body;
    
    if (!hasLlmApiKey() && !isMockMode()) {
        throw new Error('未配置 LLM API Key');
    }
    
    const analysisRaw = await callLLM(`
你是一个专业的内容分析师。请分析以下热点话题：

话题：${topic}
平台：${platform}
热度：${hot_value || '未知'}

请分析：
1. 这个话题为什么火？（核心原因）
2. 目标受众是谁？
3. 可以从哪些角度创作内容？（至少 3 个角度）
4. 有什么争议点或讨论价值？

输出格式：JSON（不要包含多余注释或说明）
{
    "reason": "火爆原因",
    "audience": "目标受众",
    "angles": ["角度 1", "角度 2", "角度 3"],
    "controversy": "争议点"
}
`);
    
    let parsed;
    try {
        parsed = JSON.parse(analysisRaw);
    } catch (e) {
        log('WARN', 'LLM 返回的分析结果不是严格 JSON，按文本返回');
        parsed = { raw: analysisRaw };
    }
    
    return response(200, {
        success: true,
        data: parsed
    });
}

// ==================== 脚本生成模块 ====================

/**
 * 生成口播稿核心逻辑（供内部复用）
 */
async function generateScriptCore({ topic, style = 'informative', duration = 60, provider } = {}) {
    if (!hasLlmApiKey(currentLlmProvider(provider)) && !isMockMode()) {
        throw new Error('未配置 LLM API Key');
    }
    
    // 计算字数（中文约 4 字/秒）
    const targetWords = duration * 4;
    
    if (isMockMode()) {
        log('INFO', 'MOCK_MODE 启用，返回模拟脚本内容');
        const mockScript = `【模拟脚本】主题：${topic}，风格：${style}，预期时长：${duration} 秒。`;
        return {
            script: mockScript,
            word_count: mockScript.length,
            estimated_duration: duration
        };
    }
    
    const script = await callLLM(`
你是一个专业的短视频口播稿写手。请根据以下主题生成一个口播稿。

主题：${topic}
风格：${style}（informative=知识科普，entertaining=娱乐搞笑，inspirational=励志鸡汤）
时长：${duration}秒（约${targetWords}字）

要求：
- 开头：用问题或金句吸引注意力（5 秒）
- 主体：3 个核心观点，每个观点配 1 个例子（${duration - 15}秒）
- 结尾：引导评论或关注（10 秒）
- 语气：自然、像和朋友聊天
- 避免：AI 味、说教感

请直接输出口播稿，不要其他说明。
`, { provider: currentLlmProvider(provider) });
    
    return {
        script,
        word_count: script.length,
        estimated_duration: Math.round(script.length / 4)
    };
}

/**
 * 生成口播稿（HTTP Handler）
 */
async function generateScript(body) {
    const { topic, style = 'informative', duration = 60, provider } = body;
    
    const data = await generateScriptCore({ topic, style, duration, provider });
    
    return response(200, {
        success: true,
        data
    });
}

// ==================== 视频生成模块 ====================

/**
 * 生成视频核心逻辑
 */
async function generateVideoCore({ script, video_type = 'talking_head' }) {
    if (!process.env.VIDEO_API_KEY && !isMockMode()) {
        throw new Error('未配置视频生成 API Key');
    }
    
    if (isMockMode()) {
        log('INFO', 'MOCK_MODE 启用，返回模拟视频生成结果');
        return {
            video_url: 'https://example.com/mock-video.mp4',
            talk_id: 'mock-talk-id'
        };
    }
    
    // 这里以 D-ID 为例（数字人视频）
    if (video_type === 'talking_head') {
        return await generateTalkingHeadVideo(script);
    }
    
    // 图文视频
    if (video_type === 'slideshow') {
        return await generateSlideshowVideo(script);
    }
    
    throw new Error('不支持的视频类型');
}

/**
 * 生成视频（HTTP Handler）
 */
async function generateVideo(body) {
    const { script, video_type = 'talking_head' } = body;
    
    const data = await generateVideoCore({ script, video_type });
    
    return response(200, {
        success: true,
        data
    });
}

/**
 * 生成数字人视频（D-ID）
 */
async function generateTalkingHeadVideo(script) {
    // D-ID API 文档：https://docs.d-id.com/
    
    // 1. 创建演讲
    let createResponse;
    try {
        createResponse = await axios.post(
            'https://api.d-id.com/talks',
            {
                script: {
                    type: 'text',
                    input: script,
                    provider: {
                        type: 'microsoft',
                        voice_id: 'zh-CN-XiaoxiaoNeural'
                    }
                },
                source_url: 'https://example.com/avatar.jpg'  // 数字人形象图片
            },
            {
                headers: {
                    'Authorization': `Basic ${process.env.VIDEO_API_KEY}`,
                    'Content-Type': 'application/json'
                }
            }
        );
    } catch (error) {
        log('ERROR', '调用 D-ID 创建视频失败:', error.message);
        throw new Error('视频生成服务调用失败，请稍后重试');
    }
    
    const talkId = createResponse.data.id;
    
    // 2. 等待视频生成（轮询）
    let status = 'created';
    let videoUrl = null;
    
    let attempts = 0;
    const maxAttempts = 40; // 最长约 2 分钟
    while ((status === 'created' || status === 'started') && attempts < maxAttempts) {
        attempts += 1;
        await sleep(3000);
        
        try {
            const statusResponse = await axios.get(
                `https://api.d-id.com/talks/${talkId}`,
                {
                    headers: {
                        'Authorization': `Basic ${process.env.VIDEO_API_KEY}`
                    }
                }
            );
            
            status = statusResponse.data.status;
            videoUrl = statusResponse.data.result_url;
        } catch (error) {
            log('ERROR', '轮询 D-ID 视频状态失败:', error.message);
            break;
        }
    }
    
    if (!videoUrl) {
        throw new Error('视频生成超时或失败');
    }
    
    return {
        video_url: videoUrl,
        talk_id: talkId
    };
}

