// ==================== 一键自动化流程 ====================

/**
 * 自动创建微信公众号文章（完整流程）
 */
async function autoCreateWeChatArticle(body) {
    const { topic, platform = 'weibo', style = 'informative', provider } = body;
    
    log('INFO', `开始自动创建微信文章：${topic}`);
    
    // 1. 生成脚本/文章内容
    log('INFO', '步骤 1/2: 生成文章内容...');
    const scriptResult = await generateScriptCore({
        topic,
        style,
        duration: 300,  // 5 分钟阅读时长
        provider
    });
    
    // 将脚本转换为微信文章格式（添加 HTML 标签）
    const articleContent = formatWeChatArticle(scriptResult.script, topic);
    log('INFO', `文章内容生成完成，${articleContent.length}字`);
    
    // 2. 发布到微信
    log('INFO', '步骤 2/2: 发布到微信公众号...');
    const publishResult = await publishWeChat({
        title: topic,
        content: articleContent,
        summary: `关于${topic}的深度解析`,
        tags: [topic.replace(/\s/g, ''), 'AI 生成', '热点解读']
    });
    
    return response(200, {
        success: true,
        data: {
            article: {
                topic,
                content: scriptResult.script,
                word_count: scriptResult.word_count
            },
            publish: JSON.parse(publishResult.body).data,
            status: 'completed'
        }
    });
}

/**
 * 将脚本格式化为微信文章 HTML
 */
function formatWeChatArticle(script, topic) {
    // 简单的 Markdown 转 HTML
    const html = script
        .split('\n')
        .map(line => {
            if (line.startsWith('# ')) {
                return `<h1>${line.slice(2)}</h1>`;
            } else if (line.startsWith('## ')) {
                return `<h2>${line.slice(3)}</h2>`;
            } else if (line.startsWith('### ')) {
                return `<h3>${line.slice(4)}</h3>`;
            } else if (line.trim()) {
                return `<p>${line}</p>`;
            }
            return '';
        })
        .join('\n');
    
    return `
<section>
    <h1 style="text-align: center; color: #333;">${topic}</h1>
    <p style="text-align: center; color: #999; font-size: 12px;">本文由 AI 自动生成</p>
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    ${html}
    <hr style="border: none; border-top: 1px solid #eee; margin: 20px 0;">
    <p style="color: #999; font-size: 12px; text-align: center;">
        🤖 本文内容由 AutoContent Factory 自动生成
    </p>
</section>
    `.trim();
}

