// ==================== 工具函数 ====================

/**
 * 调用 LLM API（支持多提供商）
 */
async function callLLM(prompt, options = {}) {
    const providerName = currentLlmProvider(options.provider);
    const provider = LLM_PROVIDERS[providerName];
    
    if (!provider) {
        throw new Error(`不支持的 LLM 提供商：${providerName}。支持的提供商：${Object.keys(LLM_PROVIDERS).join(', ')}`);
    }
    
    const apiKey = process.env.LLM_API_KEY || process.env[`${providerName.toUpperCase()}_API_KEY`];
    
    if (!apiKey && !isMockMode()) {
        throw new Error(`未配置 ${provider.name} API Key。请设置 LLM_API_KEY 或 ${providerName.toUpperCase()}_API_KEY`);
    }
    
    if (isMockMode()) {
        log('INFO', `MOCK_MODE 启用，跳过 ${provider.name} 调用`);
        return `{"reason":"示例原因","audience":"示例受众","angles":["角度 1","角度 2","角度 3"],"controversy":"示例争议点"}`;
    }
    
    const model = options.model || process.env.LLM_MODEL || provider.defaultModel;
    const baseURL = process.env.LLM_BASE_URL || provider.baseURL;
    
    log('INFO', `调用 ${provider.name} (${model})`);
    
    // Anthropic 特殊处理
    if (providerName === 'anthropic') {
        return await callAnthropic(prompt, model, apiKey, baseURL);
    }
    
    // Google Gemini 特殊处理
    if (providerName === 'google') {
        return await callGemini(prompt, model, apiKey, baseURL);
    }
    
    // 标准 OpenAI 兼容 API（阿里云、智谱、MiniMax、Moonshot、DeepSeek、OpenAI）
    const response = await axios.post(
        `${baseURL}/chat/completions`,
        {
            model: model,
            messages: [
                { role: 'user', content: prompt }
            ],
            temperature: 0.7,
            max_tokens: 2000
        },
        {
            headers: {
                'Authorization': `Bearer ${apiKey}`,
                'Content-Type': 'application/json'
            }
        }
    );
    
    return response.data.choices[0].message.content;
}

/**
 * 调用 Anthropic Claude API
 */
async function callAnthropic(prompt, model, apiKey, baseURL) {
    const response = await axios.post(
        `${baseURL}/messages`,
        {
            model: model,
            max_tokens: 2000,
            messages: [
                { role: 'user', content: prompt }
            ]
        },
        {
            headers: {
                'x-api-key': apiKey,
                'anthropic-version': '2023-06-01',
                'Content-Type': 'application/json'
            }
        }
    );
    
    return response.data.content[0].text;
}

/**
 * 调用 Google Gemini API
 */
async function callGemini(prompt, model, apiKey, baseURL) {
    const response = await axios.post(
        `${baseURL}/models/${model}:generateContent?key=${apiKey}`,
        {
            contents: [{
                parts: [{
                    text: prompt
                }]
            }]
        },
        {
            headers: {
                'Content-Type': 'application/json'
            }
        }
    );
    
    return response.data.candidates[0].content.parts[0].text;
}

/**
 * 延时函数
 */
function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * 统一响应格式
 */
function response(statusCode, body) {
    return {
        statusCode: statusCode,
        headers: {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': '*'
        },
        body: JSON.stringify(body)
    };
}

/**
 * 日志工具
 */
function log(level, ...args) {
    const timestamp = new Date().toISOString();
    console.log(`[${timestamp}][${level}]`, ...args);
}

// ==================== 本地开发服务器（便于 test.js 调用） ====================

if (require.main === module) {
    const PORT = process.env.PORT || 8000;
    
    const server = http.createServer((req, res) => {
        if (req.method !== 'POST') {
            res.writeHead(405, { 'Content-Type': 'application/json' });
            res.end(JSON.stringify({ success: false, error: 'Method Not Allowed' }));
            return;
        }
        
        let body = '';
        req.on('data', chunk => {
            body += chunk.toString();
        });
        
        req.on('end', async () => {
            try {
                const result = await exports.handler({ body }, {});
                res.writeHead(result.statusCode || 500, result.headers || { 'Content-Type': 'application/json' });
                res.end(result.body || '');
            } catch (error) {
                log('ERROR', '本地服务器处理请求失败:', error.message);
                res.writeHead(500, { 'Content-Type': 'application/json' });
                res.end(JSON.stringify({ success: false, error: error.message }));
            }
        });
    });
    
    const HOST = process.env.HOST || '127.0.0.1';
    server.listen(PORT, HOST, () => {
        log('INFO', `本地开发服务器已启动，http://${HOST}:${PORT}，MOCK_MODE=${isMockMode()}`);
    });
}
